SELECT *
FROM device_usage_record


        AND device_id = #{deviceId}


        AND device_code LIKE CONCAT('%', #{deviceCode}, '%')


        AND employee_name LIKE CONCAT('%', #{employeeName}, '%')


        AND employee_number LIKE CONCAT('%', #{employeeNumber}, '%')


        AND status IN

            #{statusVal}



        AND start_time >= #{startTimeBegin}


        AND start_time <= #{startTimeEnd}


ORDER BY start_time DESC
LIMIT #{offset}, #{limit}

